const ADD_POST = "ADDPOST";
const NEW_POST = "NEWPOST";
let initialState = {
  messegData: [{ messege: "" }],
  newChanges: "",
};
const messegDataReducer = (state = initialState, action) => {
  let copy;
  switch (action.type) {
    case NEW_POST: {
      return (copy = { ...state, newChanges: action.newChange });
    }
    case ADD_POST:
      if (state.newChanges === "") {
        return state;
      }

      return (copy = {
        ...state,
        messegData: [...state.messege, { id: 3, messege: state.newChanges }],
        newChanges: "",
      });
    default:
      return state;
  }
};

export const addPostcreateActin = () => ({ type: ADD_POST });

export const onPostChangecreateActin = (text) => ({
  type: NEW_POST,
  newChange: text,
});
export default messegDataReducer;
